// Package A: aq_schema/models/user.dart
class User {
  final String id;
  final String name;

  Map<String, dynamic> toJson() => {
    'id': id,        // ❌ Хардкод
    'name': name,    // ❌ Хардкод
  };
}

// Package B: dart_vault
class VaultStorage {
  Future<User> loadUser(Map<String, dynamic> json) {
    return User(
      id: json['id'],      // ❌ Хардкод — нарушение контракта
      name: json['name'],  // ❌ Хардкод
    );
  }
}

// ✅ ПРАВИЛЬНО
// Package A: aq_schema/models/user.dart
class User {
  static final _UserKeys _keys = _UserKeys._();
  static _UserKeys get keys => _keys;

  final String id;
  final String name;

  Map<String, dynamic> toJson() => {
    User.keys.id: id,      // ✅ Через keys
    User.keys.name: name,  // ✅ Через keys
  };

  factory User.fromJson(Map<String, dynamic> json) => User(
    id: json[User.keys.id] as String,    // ✅ Через keys
    name: json[User.keys.name] as String, // ✅ Через keys
  );
}

class _UserKeys {
  _UserKeys._();

  final String id = 'id';
  final String name = 'name';

  // Все зависимости используют переменные
  List<String> get all => [id, name];
  Set<String> get required => {id, name};
}

// Package B: dart_vault
import 'package:aq_schema/models/user.dart';

class VaultStorage {
  Future<User> loadUser(Map<String, dynamic> json) {
    return User(
      id: json[User.keys.id],      // ✅ Через keys
      name: json[User.keys.name],  // ✅ Через keys
    );
  }

  Future<void> saveUser(User user) {
    final json = {
      User.keys.id: user.id,      // ✅ Через keys
      User.keys.name: user.name,  // ✅ Через keys
    };
    await _db.insert('users', json);
  }
}

structure.code:
class MyModel {
  // 1. Приватный класс ключей
  static final _MyModelKeys _keys = _MyModelKeys._();

  // 2. Публичный геттер
  static _MyModelKeys get keys => _keys;

  // 3. Поля модели
  final String field1;
  final int field2;

  // 4. Использование keys в методах
  Map<String, dynamic> toJson() => {
    MyModel.keys.field1: field1,
    MyModel.keys.field2: field2,
  };

  factory MyModel.fromJson(Map<String, dynamic> json) => MyModel(
    field1: json[MyModel.keys.field1],
    field2: json[MyModel.keys.field2],
  );
}

// Приватный класс ключей
class _MyModelKeys {
  _MyModelKeys._(); // Приватный конструктор

  // Поля НЕ статические (доступ через экземпляр keys)
  final String field1 = 'field1';
  final String field2 = 'field2';

  // Методы используют переменные, не дублируют строки
  List<String> get all => [field1, field2];
  Set<String> get required => {field1};
  Set<String> get optional => {field2};
}

example.code:
// aq_schema/models/workflow_graph.dart
class WorkflowGraph {
  static final _WorkflowGraphKeys _keys = _WorkflowGraphKeys._();
  static _WorkflowGraphKeys get keys => _keys;

  final String id;
  final String name;
  final List<Node> nodes;

  Map<String, dynamic> toJson() => {
    WorkflowGraph.keys.id: id,
    WorkflowGraph.keys.name: name,
    WorkflowGraph.keys.nodes: nodes.map((n) => n.toJson()).toList(),
  };
}

class _WorkflowGraphKeys {
  _WorkflowGraphKeys._();

  final String id = 'id';
  final String name = 'name';
  final String nodes = 'nodes';

  List<String> get all => [id, name, nodes];
}

// dart_vault/lib/server/vault_storage.dart
import 'package:aq_schema/models/workflow_graph.dart';

class VaultStorage {
  Future<WorkflowGraph> loadGraph(String graphId) async {
    final json = await _db.query('graphs', 
      where: '${WorkflowGraph.keys.id} = ?', // ✅ Через keys
      whereArgs: [graphId],
    );

    return WorkflowGraph.fromJson(json.first);
  }

  Future<void> saveGraph(WorkflowGraph graph) async {
    await _db.insert('graphs', {
      WorkflowGraph.keys.id: graph.id,        // ✅ Через keys
      WorkflowGraph.keys.name: graph.name,    // ✅ Через keys
      WorkflowGraph.keys.nodes: jsonEncode(graph.nodes),
    });
  }
}

// core/constants/app_constants.dart
class AppConstants {
  AppConstants._();

  static const String apiBaseUrl = 'https://api.example.com/v1';
  static const int connectionTimeout = 30000;
  static const String defaultLocale = 'en';
}

class Endpoints {
  Endpoints._();

  static const String users = '/users';
  static const String graphs = '/graphs';
  static const String auth = '/auth';
}

